-- ==========================================
-- 1. СТВОРЕННЯ ТАБЛИЦЬ
-- ==========================================

CREATE TABLE "Users" (
    "UserId" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "UserLogin" VARCHAR(50) NOT NULL UNIQUE,
    "UserPassword" VARCHAR(50) NOT NULL,
    "FirstName" VARCHAR(50) NOT NULL,
    "LastName" VARCHAR(50) NOT NULL,
    "Email" VARCHAR(100) NOT NULL UNIQUE,
    "Phone" VARCHAR(16) NOT NULL UNIQUE CHECK ("Phone" LIKE '+__-___-___-____'),
    "RegistrationDate" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "Role" VARCHAR(50) NOT NULL
);

CREATE TABLE "Menu" (
    "MenuItemID" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "ItemName" VARCHAR(100) NOT NULL,
    "Description" VARCHAR(255),
    "Price" NUMERIC(10, 2) NOT NULL,
    "Weight" NUMERIC(10, 2) NOT NULL,
    "Category" VARCHAR(50) NOT NULL,
    "IsAvailable" BOOLEAN DEFAULT TRUE
);

CREATE TABLE "Orders" (
    "OrderId" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "UserId" INT NOT NULL REFERENCES "Users"("UserId") ON DELETE CASCADE,
    "OrderName" VARCHAR(100) NOT NULL,
    "OrderCount" INT NOT NULL,
    "OrderDate" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "Price" NUMERIC(10, 2) NOT NULL,
    "Status" VARCHAR(50) NOT NULL
);

