-- ==========================================
-- 3. ОНОВЛЕННЯ ПОСЛІДОВНОСТЕЙ (SEQUENCES)
-- ==========================================

SELECT setval(pg_get_serial_sequence('"Users"', 'UserId'), coalesce(max("UserId"), 1), max("UserId") IS NOT null) FROM "Users";
SELECT setval(pg_get_serial_sequence('"Menu"', 'MenuItemID'), coalesce(max("MenuItemID"), 1), max("MenuItemID") IS NOT null) FROM "Menu";
SELECT setval(pg_get_serial_sequence('"Orders"', 'OrderId'), coalesce(max("OrderId"), 1), max("OrderId") IS NOT null) FROM "Orders";